mapper.select:
select tenant_id
from batch.pipeline_instance
where id = #{pipelineInstanceId}

select s.id, s.pipeline_instance_id, s.step_code, s.stage_code, s.run_seq, s.step_status, s.input_summary, s.output_summary, s.error_code, s.error_message, s.error_key, s.error_args, s.retry_count, s.duration_ms, s.started_at, s.finished_at from batch.pipeline_step_run s join batch.pipeline_instance p on p.id = s.pipeline_instance_id where p.tenant_id = #{tenantId}
and s.pipeline_instance_id = #{pipelineInstanceId}
and s.step_code = #{stepCode}
and s.stage_code = #{stageCode}
and s.step_status = #{stepStatus}
order by s.pipeline_instance_id desc, s.id desc
limit #{pageRequest.pageSize} offset (#{pageRequest.pageNo} - 1) * #{pageRequest.pageSize}

select count(1)
from batch.pipeline_step_run s
join batch.pipeline_instance p on p.id = s.pipeline_instance_id
where p.tenant_id = #{tenantId}

    and s.pipeline_instance_id = #{pipelineInstanceId}


    and s.step_code = #{stepCode}


    and s.stage_code = #{stageCode}


    and s.step_status = #{stepStatus}
